// ============================================
// EXTRAER + CODIFICAR ARCHIVO
// Valida campos y convierte binario a base64
// (el binario se perdería al pasar por GSheets)
// ============================================
const item = $input.first();
const body = item.json.body || item.json;
const cotizacion_id = (body.cotizacion_id || '').trim();
const telefono      = (body.telefono      || '').trim();

// Validar cotizacion_id
if (!cotizacion_id) {
  return [{
    json: {
      valido:    false,
      error_code: 400,
      error_msg: 'cotizacion_id es requerido'
    }
  }];
}

// Validar que llegó un archivo
const binaryKeys = Object.keys(item.binary || {});
if (binaryKeys.length === 0) {
  return [{
    json: {
      valido:     false,
      error_code: 400,
      error_msg:  'Archivo de comprobante requerido',
      cotizacion_id
    }
  }];
}

// Codificar a base64 para sobrevivir el paso por Google Sheets
const binaryKey    = binaryKeys[0];
const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const fileBase64   = binaryBuffer.toString('base64');
const fileMime     = item.binary[binaryKey].mimeType || 'image/jpeg';
const fileName     = item.binary[binaryKey].fileName || 'comprobante.jpg';

return [{
  json: {
    valido: true,
    cotizacion_id,
    telefono,
    fileBase64,
    fileMime,
    fileName
  }
}];

// ============================================
// VALIDAR COTIZACION + ESTADO
// Verifica existencia y que el estado permita
// enviar un comprobante de pago
// ============================================
const inputData     = $('Extraer + Codificar Archivo').first().json;
const cotizacion_id = inputData.cotizacion_id;

const todasLasCotizaciones = $input.all();
const fila = todasLasCotizaciones
  .find(item => item.json.cotizacion_id === cotizacion_id)
  ?.json;

// Validar existencia
if (!fila) {
  return [{
    json: {
      ...inputData,
      cotizacion_ok: false,
      error_code:    404,
      error_msg:     'Cotización no encontrada: ' + cotizacion_id
    }
  }];
}

// Solo se puede enviar comprobante después de elegir opción
const estadosPermitidos = ['elegido_marca', 'elegido_economico'];

if (!estadosPermitidos.includes(fila.estado)) {
  let error_code = 422;
  let error_msg;

  if (fila.estado === 'comprobante_enviado') {
    error_code = 409;
    error_msg  = 'Ya existe un comprobante enviado para esta cotización.';
  } else if (fila.estado === 'verificado') {
    error_code = 409;
    error_msg  = 'Esta cotización ya fue verificada y procesada.';
  } else if (fila.estado === 'cotizado') {
    error_msg  = 'Debes confirmar tu opción (marca o económica) antes de enviar el comprobante.';
  } else {
    error_msg  = 'Estado incompatible para envío de comprobante: "' + fila.estado + '"';
  }

  return [{
    json: {
      ...inputData,
      cotizacion_ok: false,
      error_code,
      error_msg,
      estado_actual: fila.estado
    }
  }];
}

// Cotización válida para recibir comprobante
return [{
  json: {
    ...inputData,
    cotizacion_ok:   true,
    nombre:          fila.nombre || '',
    opcion:          fila.estado.replace('elegido_', ''),
    estado_anterior: fila.estado
  }
}];

// ============================================
// RESTAURAR BINARIO PARA TELEGRAM
// El nodo Google Sheets no pasa datos binarios.
// Reconstruimos desde el base64 guardado en JSON
// para que el nodo Telegram pueda enviarlo.
// ============================================
const d = $input.first().json;

const buffer     = Buffer.from(d.fileBase64, 'base64');
const binaryData = await this.helpers.prepareBinaryData(
  buffer,
  d.fileName,
  d.fileMime
);

return [{
  json: d,
  binary: { comprobante: binaryData }
}];
